/* ==================== GLOBAL RESET ==================== */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    /* Color Palette - Dark Theme */
    --bg-primary: #1a2332;
    --bg-secondary: #243447;
    --bg-card: #2a3f5f;
    --text-primary: #ffffff;
    --text-secondary: #b0c4de;
    --accent-teal: #4ecdc4;
    --accent-yellow: #ffd166;
    --accent-pink: #ff6b9d;
    --accent-purple: #c77dff;
    --accent-green: #06ffa5;
    --accent-red: #ff4757;
    --border-color: #3d5a80;
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: var(--bg-primary);
    color: var(--text-primary);
    overflow-x: hidden;
}

/* ==================== APP CONTAINER ==================== */

.app-container {
    display: flex;
    min-height: 100vh;
}

/* ==================== SIDEBAR ==================== */

.sidebar {
    width: 250px;
    background: #1a1f3a;
    padding: 30px 20px;
    display: flex;
    flex-direction: column;
    position: fixed;
    height: 100vh;
    border-right: 1px solid var(--border-color);
}

.logo {
    margin-bottom: 50px;
}

.logo h1 {
    font-size: 1.5em;
    font-weight: 600;
    letter-spacing: 2px;
    color: var(--text-primary);
}

.beta-badge {
    display: inline-block;
    background: var(--accent-pink);
    color: white;
    font-size: 0.7em;
    padding: 3px 8px;
    border-radius: 4px;
    margin-left: 10px;
    font-weight: bold;
}

.nav-menu {
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.nav-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 15px 20px;
    color: var(--text-secondary);
    text-decoration: none;
    border-radius: 8px;
    transition: all 0.3s ease;
    font-size: 0.95em;
}

.nav-item:hover {
    background: var(--bg-secondary);
    color: var(--text-primary);
}

.nav-item.active {
    background: var(--bg-secondary);
    color: var(--text-primary);
    border-left: 4px solid var(--accent-teal);
}

.nav-item .icon {
    font-size: 1.2em;
}

/* ==================== MAIN CONTENT ==================== */

.main-content {
    flex: 1;
    margin-left: 250px;
    background: var(--bg-primary);
    padding: 30px;
}

/* ==================== HEADER ==================== */

.header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 30px;
}

.header h2 {
    font-size: 2em;
    font-weight: 400;
    color: var(--text-primary);
}

.header-right {
    display: flex;
    align-items: center;
    gap: 30px;
}

.time-filter {
    display: flex;
    gap: 0;
    background: var(--bg-secondary);
    border-radius: 25px;
    padding: 5px;
}

.filter-btn {
    padding: 10px 20px;
    background: transparent;
    border: none;
    color: var(--text-secondary);
    font-size: 0.85em;
    font-weight: 600;
    cursor: pointer;
    border-radius: 20px;
    transition: all 0.3s ease;
}

.filter-btn:hover {
    color: var(--text-primary);
}

.filter-btn.active {
    background: var(--bg-card);
    color: var(--text-primary);
}

.date-display {
    color: var(--text-secondary);
    font-size: 0.95em;
}

/* ==================== DASHBOARD GRID ==================== */

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 25px;
}

/* ==================== CARD STYLES ==================== */

.card {
    background: var(--bg-card);
    border-radius: 15px;
    padding: 25px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
    transition: transform 0.3s ease;
}

.card:hover {
    transform: translateY(-5px);
}

.card-title {
    font-size: 0.85em;
    font-weight: 600;
    color: var(--text-secondary);
    letter-spacing: 1px;
    margin-bottom: 20px;
    text-transform: uppercase;
}

/* ==================== COST PREDICTED ==================== */

.chart-container {
    position: relative;
    height: 200px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.chart-center-text {
    position: absolute;
    text-align: center;
    pointer-events: none;
}

.total-label {
    font-size: 0.9em;
    color: var(--text-secondary);
}

.total-value {
    font-size: 2em;
    font-weight: bold;
    color: var(--text-primary);
    margin-top: 5px;
}

.chart-legend {
    display: flex;
    justify-content: center;
    gap: 30px;
    margin-top: 20px;
}

.legend-item {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.9em;
    color: var(--text-secondary);
}

.legend-dot {
    width: 12px;
    height: 12px;
    border-radius: 3px;
}

.legend-dot.electricity {
    background: var(--accent-teal);
}

.legend-dot.gas {
    background: var(--accent-yellow);
}

/* ==================== CHANGE IN COST ==================== */

.cost-comparison {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 20px 0;
}

.cost-bar-container {
    display: flex;
    gap: 30px;
    flex: 1;
}

.cost-bar {
    text-align: center;
}

.bar-value {
    font-size: 1.8em;
    font-weight: bold;
    color: var(--accent-teal);
    margin-bottom: 10px;
}

.bar-label {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.cost-change {
    text-align: center;
    padding: 20px;
}

.change-icon {
    font-size: 2em;
    color: var(--accent-red);
    margin-bottom: 5px;
}

.change-percentage {
    font-size: 2em;
    font-weight: bold;
    color: var(--accent-red);
    margin-bottom: 5px;
}

.change-label {
    font-size: 0.75em;
    color: var(--text-secondary);
    letter-spacing: 1px;
}

/* ==================== USAGE ESTIMATE ==================== */

.usage-stats {
    display: flex;
    justify-content: space-between;
    margin-bottom: 20px;
}

.stat-item {
    display: flex;
    flex-direction: column;
    gap: 5px;
}

.stat-label {
    font-size: 0.85em;
    color: var(--text-secondary);
}

.stat-value {
    font-size: 1.1em;
    font-weight: bold;
    color: var(--text-primary);
}

/* ==================== ACTIVE APPLIANCES ==================== */

.appliances-list {
    display: flex;
    flex-direction: column;
    gap: 15px;
}

.appliance-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 0;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.appliance-name {
    display: flex;
    align-items: center;
    gap: 10px;
    color: var(--text-primary);
}

.appliance-bar {
    width: 120px;
    height: 8px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 4px;
    overflow: hidden;
    margin-right: 10px;
}

.appliance-bar-fill {
    height: 100%;
    border-radius: 4px;
    transition: width 0.3s ease;
}

.appliance-value {
    font-weight: 600;
    color: var(--text-primary);
    min-width: 60px;
    text-align: right;
}

/* ==================== AQI SECTION ==================== */

.aqi-status {
    display: flex;
    justify-content: space-around;
    margin-top: 20px;
    padding-top: 15px;
    border-top: 1px solid rgba(255, 255, 255, 0.1);
}

.aqi-location {
    font-size: 0.9em;
    color: var(--text-secondary);
}

.aqi-location span {
    font-weight: bold;
    color: var(--accent-teal);
}

/* ==================== CARBON FOOTPRINT ==================== */

.emission-data {
    margin-bottom: 25px;
}

.emission-row {
    display: flex;
    justify-content: space-between;
    padding: 10px 0;
    font-size: 0.9em;
}

.emission-label {
    color: var(--text-secondary);
    font-weight: 600;
}

.emission-value {
    color: var(--text-primary);
}

.emission-value.predicted {
    color: var(--text-secondary);
}

.emission-row.highlight {
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    margin: 10px 0;
    padding: 15px 0;
}

.emission-row.highlight .emission-value {
    font-weight: bold;
    font-size: 1.05em;
}

.green-energy {
    margin-top: 20px;
}

.green-label {
    font-size: 0.9em;
    color: var(--text-secondary);
    margin-bottom: 10px;
}

.green-bar {
    width: 100%;
    height: 12px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 6px;
    overflow: hidden;
    margin-bottom: 10px;
}

.green-progress {
    height: 100%;
    background: var(--accent-green);
    border-radius: 6px;
    transition: width 0.5s ease;
}

.green-stats {
    display: flex;
    justify-content: space-between;
    font-size: 0.85em;
    color: var(--text-secondary);
}

.green-stats strong {
    color: var(--accent-green);
}

.goal-text {
    color: var(--text-secondary);
}

.goal-text strong {
    color: var(--text-primary);
}

/* ==================== RESPONSIVE DESIGN ==================== */

@media (max-width: 1400px) {
    .dashboard-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 900px) {
    .sidebar {
        width: 70px;
        padding: 20px 10px;
    }

    .logo h1,
    .beta-badge,
    .nav-item span:not(.icon) {
        display: none;
    }

    .nav-item {
        justify-content: center;
        padding: 15px;
    }

    .main-content {
        margin-left: 70px;
    }

    .dashboard-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 600px) {
    .header {
        flex-direction: column;
        gap: 15px;
        align-items: flex-start;
    }

    .cost-comparison {
        flex-direction: column;
        gap: 20px;
    }
}

// ==================== CONFIGURATION ====================

const API_BASE_URL = 'http://localhost:5000';
const REFRESH_INTERVAL = 30000;

let costChart = null;
let usageChart = null;
let aqiGauge = null;

// ==================== UTILITY FUNCTIONS ====================

function formatCurrency(value) {
    return `$${value.toFixed(0)}`;
}

function formatDate() {
    const now = new Date();
    const options = { month: 'long', year: 'numeric' };
    return now.toLocaleDateString('en-US', options);
}

function getAQICategory(aqiValue) {
    if (aqiValue <= 50) return { category: 'Good', color: '#06ffa5' };
    else if (aqiValue <= 100) return { category: 'Moderate', color: '#ffd166' };
    else if (aqiValue <= 150) return { category: 'Unhealthy for Sensitive', color: '#ff9f40' };
    else if (aqiValue <= 200) return { category: 'Unhealthy', color: '#ff6b9d' };
    else if (aqiValue <= 300) return { category: 'Very Unhealthy', color: '#c77dff' };
    else return { category: 'Hazardous', color: '#ff4757' };
}

// ==================== FETCH DATA FUNCTIONS ====================

async function fetchLatestAQI() {
    try {
        const response = await fetch(`${API_BASE_URL}/api/aqi/latest`);
        const result = await response.json();

        if (result.status === 'success') {
            updateAQIDisplay(result.data);
        }
    } catch (error) {
        console.error('Error fetching AQI data:', error);
    }
}

async function fetchElectricityData() {
    try {
        const response = await fetch(`${API_BASE_URL}/api/electricity/history?limit=100`);
        const result = await response.json();

        if (result.status === 'success') {
            updateAppliancesDisplay(result.data);
            updateCostPredicted(result.data);
            updateUsageEstimate(result.data);
            updateCarbonFootprint(result.data);
        }
    } catch (error) {
        console.error('Error fetching electricity data:', error);
    }
}

// ==================== UPDATE DISPLAY FUNCTIONS ====================

function updateAQIDisplay(data) {
    let avgAQI = 0;
    let count = 0;

    if (data.indoor) {
        document.getElementById('indoorAQI').textContent = data.indoor.aqi_value;
        avgAQI += data.indoor.aqi_value;
        count++;
    }

    if (data.outdoor) {
        document.getElementById('outdoorAQI').textContent = data.outdoor.aqi_value;
        avgAQI += data.outdoor.aqi_value;
        count++;
    }

    if (count > 0) {
        avgAQI = Math.round(avgAQI / count);
        document.getElementById('aqiValue').textContent = avgAQI;
        createAQIGauge(avgAQI);
    }
}

function updateAppliancesDisplay(data) {
    const appliancesList = document.getElementById('appliancesList');

    // Get latest reading for each device
    const deviceMap = {};
    data.forEach(record => {
        if (!deviceMap[record.device_name] || 
            new Date(record.timestamp) > new Date(deviceMap[record.device_name].timestamp)) {
            deviceMap[record.device_name] = record;
        }
    });

    // Define colors for each appliance
    const colors = {
        'TV': '#ff6b9d',
        'Router': '#c77dff',
        'Charger': '#4ecdc4',
        'Refrigerator': '#ffd166'
    };

    // Sort by power consumption
    const devices = Object.values(deviceMap).sort((a, b) => b.power_watts - a.power_watts);

    let html = '';
    devices.forEach(device => {
        const maxPower = 200; // Maximum power for bar width calculation
        const barWidth = Math.min((device.power_watts / maxPower) * 100, 100);
        const color = colors[device.device_name] || '#4ecdc4';

        html += `
            <div class="appliance-item">
                <div class="appliance-name">${device.device_name}</div>
                <div class="appliance-bar">
                    <div class="appliance-bar-fill" style="width: ${barWidth}%; background: ${color};"></div>
                </div>
                <div class="appliance-value">${device.power_watts.toFixed(1)} kWh</div>
            </div>
        `;
    });

    appliancesList.innerHTML = html;
}

function updateCostPredicted(data) {
    // Calculate total power consumption
    let totalPower = 0;
    data.forEach(record => {
        totalPower += record.power_watts;
    });

    // Estimate cost (assuming $0.12 per kWh)
    const avgPowerKW = totalPower / data.length / 1000;
    const hoursPerMonth = 730;
    const costPerKWh = 0.12;
    const totalCost = avgPowerKW * hoursPerMonth * costPerKWh;

    // Split between electricity (80%) and gas (20%)
    const electricityCost = totalCost * 0.8;
    const gasCost = totalCost * 0.2;

    document.getElementById('totalCost').textContent = formatCurrency(totalCost);

    // Update cost comparison
    const lastMonthCost = totalCost * 0.95; // Simulate last month (5% less)
    const changePercent = ((totalCost - lastMonthCost) / lastMonthCost * 100).toFixed(2);

    document.getElementById('lastMonthValue').textContent = formatCurrency(lastMonthCost);
    document.getElementById('currentMonthValue').textContent = formatCurrency(totalCost);
    document.getElementById('changePercentage').textContent = `${changePercent}%`;

    createCostChart(electricityCost, gasCost);
}

function updateUsageEstimate(data) {
    // Calculate usage
    let totalPower = 0;
    data.forEach(record => {
        totalPower += record.power_watts;
    });

    const avgPowerKW = totalPower / data.length / 1000;
    const currentDay = new Date().getDate();
    const daysInMonth = 30;

    const usageTillNow = avgPowerKW * currentDay * 24;
    const usagePredicted = avgPowerKW * daysInMonth * 24;

    document.getElementById('usageTillNow').textContent = `${usageTillNow.toFixed(1)} kWh`;
    document.getElementById('usagePredicted').textContent = `${usagePredicted.toFixed(1)} kWh`;

    createUsageChart(usageTillNow, usagePredicted);
}

function updateCarbonFootprint(data) {
    // Calculate emissions (0.92 lbs CO2 per kWh = 0.417 kg CO2 per kWh)
    let totalPower = 0;
    data.forEach(record => {
        totalPower += record.power_watts;
    });

    const avgPowerKW = totalPower / data.length / 1000;
    const currentDay = new Date().getDate();
    const daysInMonth = 30;

    const usageTillNow = avgPowerKW * currentDay * 24;
    const usagePredicted = avgPowerKW * daysInMonth * 24;

    const emissionTillDate = usageTillNow * 0.417;
    const emissionPredicted = usagePredicted * 0.417;

    document.getElementById('emissionTillDate').textContent = `${emissionTillDate.toFixed(1)} Kg of CO2`;
    document.getElementById('emissionPredicted').textContent = `${emissionPredicted.toFixed(1)} Kg of CO2`;

    // Green energy (simulate 30% of usage)
    const greenEnergy = usageTillNow * 0.3;
    const greenGoal = 500;
    const greenPercent = Math.min((greenEnergy / greenGoal) * 100, 100);

    document.getElementById('greenCurrent').textContent = `${greenEnergy.toFixed(0)} kWh`;
    document.getElementById('greenProgress').style.width = `${greenPercent}%`;
}

// ==================== CHART FUNCTIONS ====================

function createCostChart(electricityCost, gasCost) {
    const ctx = document.getElementById('costChart');
    if (!ctx) return;

    if (costChart) {
        costChart.destroy();
    }

    costChart = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: ['Electricity', 'Gas'],
            datasets: [{
                data: [electricityCost, gasCost],
                backgroundColor: ['#4ecdc4', '#ffd166'],
                borderWidth: 0
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            cutout: '75%',
            plugins: {
                legend: {
                    display: false
                },
                tooltip: {
                    callbacks: {
                        label: function(context) {
                            return context.label + ': $' + context.parsed.toFixed(2);
                        }
                    }
                }
            }
        }
    });
}

function createUsageChart(tillNow, predicted) {
    const ctx = document.getElementById('usageChart');
    if (!ctx) return;

    if (usageChart) {
        usageChart.destroy();
    }

    // Generate data for the month
    const currentDay = new Date().getDate();
    const labels = [];
    const data = [];

    for (let i = 1; i <= 30; i++) {
        labels.push(`Jun ${i}`);
        if (i <= currentDay) {
            data.push((tillNow / currentDay) * i);
        } else {
            data.push(null);
        }
    }

    usageChart = new Chart(ctx, {
        type: 'line',
        data: {
            labels: labels,
            datasets: [{
                data: data,
                borderColor: '#ff6b9d',
                backgroundColor: 'rgba(255, 107, 157, 0.1)',
                fill: true,
                tension: 0.4,
                pointRadius: 4,
                pointBackgroundColor: '#ff6b9d',
                pointBorderColor: '#fff',
                pointBorderWidth: 2
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    display: false
                }
            },
            scales: {
                x: {
                    display: true,
                    grid: {
                        color: 'rgba(255, 255, 255, 0.05)'
                    },
                    ticks: {
                        color: '#b0c4de',
                        maxRotation: 0,
                        autoSkip: true,
                        maxTicksLimit: 6
                    }
                },
                y: {
                    display: true,
                    grid: {
                        color: 'rgba(255, 255, 255, 0.05)'
                    },
                    ticks: {
                        color: '#b0c4de'
                    }
                }
            }
        }
    });
}

function createAQIGauge(aqiValue) {
    const ctx = document.getElementById('aqiGauge');
    if (!ctx) return;

    if (aqiGauge) {
        aqiGauge.destroy();
    }

    const aqiInfo = getAQICategory(aqiValue);
    const maxAQI = 500;
    const percentage = (aqiValue / maxAQI) * 100;

    aqiGauge = new Chart(ctx, {
        type: 'doughnut',
        data: {
            datasets: [{
                data: [percentage, 100 - percentage],
                backgroundColor: [aqiInfo.color, 'rgba(255, 255, 255, 0.1)'],
                borderWidth: 0
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            cutout: '75%',
            rotation: -90,
            circumference: 180,
            plugins: {
                legend: {
                    display: false
                },
                tooltip: {
                    enabled: false
                }
            }
        }
    });
}

// ==================== INITIALIZATION ====================

async function refreshDashboard() {
    console.log('Refreshing dashboard...');
    document.getElementById('currentDate').textContent = formatDate();

    await Promise.all([
        fetchLatestAQI(),
        fetchElectricityData()
    ]);
}

window.addEventListener('DOMContentLoaded', () => {
    console.log('EcoTrack Dashboard Initialized');
    refreshDashboard();
    setInterval(refreshDashboard, REFRESH_INTERVAL);
});
